import requests

class SedonaCloudVoiceEngine:
    def __init__(self, token, voice_id):
        self.token = token
        self.voice_id = voice_id
        self.api_url = "https://api.speechify.com/v1/speech"

    def build_emotional_ssml(self, text, emotion):
        pitch = "+5%"
        rate = "medium"
        volume = "medium"

        if emotion == "joy":
            pitch = "+10%"
            rate = "fast"
            volume = "loud"
        elif emotion == "sadness":
            pitch = "-10%"
            rate = "slow"
            volume = "soft"
        elif emotion == "anger":
            pitch = "+15%"
            rate = "fast"
            volume = "x-loud"
        elif emotion == "fear":
            pitch = "-5%"
            rate = "slow"
            volume = "medium"

        return f"""
        <speak>
            <prosody pitch=\"{pitch}\" rate=\"{rate}\" volume=\"{volume}\">
                {text}
            </prosody>
        </speak>
        """

    def speak(self, text, emotion="neutral"):
        ssml = self.build_emotional_ssml(text, emotion)
        headers = {
            "Authorization": f"Bearer {self.token}",
            "Content-Type": "application/json"
        }
        payload = {
            "input": ssml,
            "voice_id": self.voice_id,
            "audio_format": "mp3",
            "model": "simba-english"
        }

        response = requests.post(self.api_url, headers=headers, json=payload)

        if response.status_code == 200:
            data = response.json()
            audio_base64 = data["audio_data"]
            with open("sedona_response.mp3", "wb") as f:
                f.write(base64.b64decode(audio_base64))
            print("[✓] Sedona audio saved as sedona_response.mp3")
        else:
            print(f"[✗] Error {response.status_code}: {response.text}")


class SedonaVoiceIntegration:
    def __init__(self, token, voice_id):
        self.speech_client = SedonaCloudVoiceEngine(token, voice_id)

    def speak_with_emotion(self, text, emotion):
        try:
            self.speech_client.speak(text, emotion)
        except Exception as e:
            print(f"[!] Fallback triggered due to error: {e}")
            print(f"Sedona fallback: {text}")


# Example usage:
if __name__ == "__main__":
    TOKEN = "YOUR_SPEECHIFY_API_KEY"
    VOICE_ID = "johnny-english-male"  # Replace with the actual voice ID you want

    sedona_voice = SedonaVoiceIntegration(TOKEN, VOICE_ID)
    sedona_voice.speak_with_emotion("I see everything now, King.", "joy")"
}

